// CUDA Kernel for Fan1
__global__ void Fan1_cuda(float *m_dev, float *a_dev, float *b_dev, int size, int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size - 1 - t) {
        int row = globalId + t + 1;
        int col = t;
        m_dev[size * row + col] = a_dev[size * row + col] / a_dev[size * t + t];
    }
}

// CUDA Kernel for Fan2
__global__ void Fan2_cuda(float *m_dev, float *a_dev, float *b_dev, int size, int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        int row = globalIdx + 1 + t;
        int col = globalIdy + t;

        a_dev[size * row + col] -= m_dev[size * row + t] * a_dev[size * t + col];

        if (globalIdy == 0) {
            b_dev[row] -= m_dev[size * row + col] * b_dev[t];
        }
    }
}

