float eventTime(cudaEvent_t event) {
    float elapsed = 0.0f;
    cudaEventRecord(event);
    cudaEventSynchronize(event);
    cudaEventElapsedTime(&elapsed, event);
    return elapsed; // Returns milliseconds, OpenCL was microseconds, but logic adjusted for CUDA event API
}

void ForwardSub(float *a, float *b, float *m, int size, int timing) {
    float *d_a, *d_b, *d_m;
    size_t bytes_a = size * size * sizeof(float);
    size_t bytes_b = size * sizeof(float);
    size_t bytes_m = size * size * sizeof(float);

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    // Allocate memory
    if (timing) gettimeofday(&tv_mem_alloc_start, NULL);
    cudaMalloc(&d_a, bytes_a);
    cudaMalloc(&d_b, bytes_b);
    cudaMalloc(&d_m, bytes_m);
    if (timing) {
        gettimeofday(&tv_mem_alloc_end, NULL);
        tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
        mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    }

    // Copy input data to device
    if (timing) gettimeofday(&tv_h2d_start, NULL);
    cudaMemcpy(d_a, a, bytes_a, cudaMemcpyHostToDevice);
    cudaMemcpy(d_b, b, bytes_b, cudaMemcpyHostToDevice);
    cudaMemcpy(d_m, m, bytes_m, cudaMemcpyHostToDevice);
    if (timing) {
        gettimeofday(&tv_h2d_end, NULL);
        tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
        h2d_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    }

    // Define block and grid sizes
    dim3 block1(BLOCK_SIZE_0, 1, 1);
    dim3 block2(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y, 1);

    // Grid size calculation (ceil division)
    int grid1_x = (size - 1) / block1.x + 1;
    int grid2_x = (size - 1) / block2.x + 1;
    int grid2_y = (size) / block2.y + 1;

    dim3 grid1(grid1_x, 1, 1);
    dim3 grid2(grid2_x, grid2_y, 1);

    float writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);
    float readMB = writeMB;

    if (timing) gettimeofday(&tv_kernel_start, NULL);
    cudaEventRecord(start);

    int t;
    for (t = 0; t < (size - 1); t++) {
        // Launch Fan1
        Fan1_cuda<<<grid1, block1>>>(d_m, d_a, d_b, size, t);

        // Launch Fan2
        Fan2_cuda<<<grid2, block2>>>(d_m, d_a, d_b, size, t);
    }

    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    if (timing) {
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

        float elapsed = 0.0f;
        cudaEventElapsedTime(&elapsed, start, stop);
        kernel_time = elapsed; // Use precise GPU timing
    }

    // Copy results back to host
    if (timing) gettimeofday(&tv_d2h_start, NULL);
    cudaMemcpy(a, d_a, bytes_a, cudaMemcpyDeviceToHost);
    cudaMemcpy(b, d_b, bytes_b, cudaMemcpyDeviceToHost);
    cudaMemcpy(m, d_m, bytes_m, cudaMemcpyDeviceToHost);
    if (timing) {
        gettimeofday(&tv_d2h_end, NULL);
        tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
        d2h_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    }

    if (timing) {
        printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%dx%d      \t", size, size);
        printf("%f [%.2fMB]\t", h2d_time, writeMB);
        printf("%f\t", kernel_time);
        printf("%f [%.2fMB]\t", d2h_time, readMB);
        printf("%f\n\n", h2d_time + kernel_time + d2h_time);
    }

    // Cleanup
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_m);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);
}

int main(int argc, char *argv[]) {
    printf("WG size of kernel 1 = %d, WG size of kernel 2= %d X %d\n", BLOCK_SIZE_0, BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);

    float *a = NULL, *b = NULL, *finalVec = NULL;
    float *m = NULL;
    int size = -1;
    FILE *fp;
    char filename[200];
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    if (parseCommandline(argc, argv, filename, &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    if (size < 1) {
        fp = fopen(filename, "r");
        if (!fp) {
            printf("Error opening file %s\n", filename);
            return -1;
        }
        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);
        a = (float *)malloc(size * size * sizeof(float));
        create_matrix(a, size);

        b = (float *)malloc(size * sizeof(float));
        for (int i = 0; i < size; i++)
            b[i] = 1.0;
    }

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);
        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));

    InitPerRun(size, m);

    // Initialize CUDA
    cudaSetDevice(device); // Simplified device selection

    ForwardSub(a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
